array.string:
export PATH="$HOME/.local/bin:/usr/local/bin:/opt/homebrew/bin:$PATH";
cd /Users/tm/Projects/Claude/ResearchMan;
LOG=$HOME/Library/Logs/researchman-tech.log;
[ -f $LOG ] && [ $(stat -f%z $LOG) -gt 5242880 ] && mv $LOG $LOG.1;
node scripts/run-if-due.mjs --state .last-tech-research-run.txt --daily-at 10 >> $LOG 2>&1 || exit 0;
# Case Study側(autoresearch)と同時発火した際のgit競合を防ぐ排他ロック（最大30分待ち）。
# ロックが90分超残存していたらkill -9等の残骸とみなし奪取する（3ジョブ合計でも90分あれば完走する）
LOCK=/tmp/researchman-git.lock; waited=0;
while ! mkdir $LOCK 2>/dev/null; do
  if [ -d $LOCK ] && [ $(( $(date +%s) - $(stat -f %m $LOCK) )) -gt 5400 ]; then
    echo "staleロック奪取: $(date)" >> $LOG; rmdir $LOCK 2>/dev/null; continue;
  fi;
  sleep 30; waited=$((waited+30));
  [ $waited -ge 1800 ] && { echo "ロック取得タイムアウト: $(date)" >> $LOG; exit 0; };
done;
trap "rmdir $LOCK 2>/dev/null" EXIT;
echo "===== Tech run start: $(date) =====" >> $LOG;
if ! node scripts/auto-research-tech.mjs >> $LOG 2>&1; then
  echo "収集エラー終了: $(date)" >> $LOG;
  node scripts/run-if-due.mjs --state .last-tech-research-run.txt --mark >> $LOG 2>&1;
  node scripts/notify-line.mjs --result error --route technology --label Technology >> $LOG 2>&1;
  exit 0;
fi;
git add data/tech.json public/thumbnails/tech/ >> $LOG 2>&1;
if git diff --cached --quiet; then
  echo "変更なし（新規技術なし）: $(date)" >> $LOG;
  node scripts/notify-line.mjs --summary /tmp/researchman-tech-last-add.json --route technology --label Technology >> $LOG 2>&1;
else
  git commit -m "Tech radar: $(date '+%Y-%m-%d')" >> $LOG 2>&1;
  if git push >> $LOG 2>&1; then
    if node scripts/verify-deploy.mjs --skip-pages >> $LOG 2>&1 && node scripts/verify-tech-pages.mjs >> $LOG 2>&1; then
      echo "反映まで確認OK: $(date)" >> $LOG;
      node scripts/notify-line.mjs --summary /tmp/researchman-tech-last-add.json --route technology --label Technology >> $LOG 2>&1;
    else
      echo "push成功だが反映未確認（時間切れ）: $(date)" >> $LOG;
      node scripts/notify-line.mjs --result unverified --summary /tmp/researchman-tech-last-add.json --route technology --label Technology >> $LOG 2>&1;
    fi;
  else
    echo "push失敗（pre-push監査で中止の可能性）。コミットはローカル残存。要手動対応: $(date)" >> $LOG;
    node scripts/notify-line.mjs --result pushfail --summary /tmp/researchman-tech-last-add.json --route technology --label Technology >> $LOG 2>&1;
  fi;
fi;
echo "Tech completed: $(date)" >> $LOG
